import React from 'react';
import PhotoSide from '../components/PhotoSide';
import { Outlet, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import './AuthLayout.css';

function AuthLayout() {
  const location = useLocation();
  const reverseRoutes = ['/forgot-password', '/reset-password'];
  const isReverse = reverseRoutes.includes(location.pathname);

  return (
    <div className="auth-container">
      <AnimatePresence mode="wait">
        <motion.div
          key={`photo-${isReverse ? 'right' : 'left'}`}
          className="photo-side"
          initial={{ x: isReverse ? 0 : 0 }}
          animate={{ x: isReverse ? '100%' : '0%' }}
          exit={{ x: isReverse ? '0%' : '-100%', opacity: 0 }}
          transition={{ duration: 0.6, ease: 'easeInOut' }}
        >
          <PhotoSide />
        </motion.div>
      </AnimatePresence>

      <AnimatePresence mode="wait">
        <motion.div
          key={`form-${isReverse ? 'left' : 'right'}`}
          className="form-side"
          initial={{ x: isReverse ? '-100%' : '100%', opacity: 0 }}
          animate={{ x: '0%', opacity: 1 }}
          exit={{ x: isReverse ? '100%' : '-100%', opacity: 0 }}
          transition={{ duration: 0.6, ease: 'easeInOut' }}
        >
          <Outlet />
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

export default AuthLayout;
